### Creating Spherical Joint in React Three Rapier (TSX)

Source: https://github.com/pmndrs/react-three-rapier/blob/main/packages/react-three-rapier/readme.md

Illustrates the usage of the useSphericalJoint hook to connect two rigid bodies at specific points, preventing relative translation at those points. It requires refs to the rigid bodies and specifies the joint's position in local space for both bodies.

```tsx
const JointedThing = () => {
  const bodyA = useRef<RapierRigidBody>(null);
  const bodyB = useRef<RapierRigidBody>(null);

  const joint = useSphericalJoint(bodyA, bodyB, [
    // Position of the joint in bodyA's local space
    [0, 0, 0],
    // Position of the joint in bodyB's local space
    [0, 0, 0]
  ]);

  return (
    <group>
      <RigidBody ref={bodyA}>
        <mesh />
      </RigidBody>
      <RigidBody ref={bodyB}>
        <mesh />
      </RigidBody>
    </group>
  );
};
```

