### Applying Forces and Torques to RigidBody (react-three-rapier, TSX)

Source: https://github.com/pmndrs/react-three-rapier/blob/main/packages/react-three-rapier/readme.md

Demonstrates how to get a reference to a RigidBody instance and use its methods (applyImpulse, addForce, applyTorqueImpulse, addTorque) to manipulate its motion and rotation. Mentions the use of useRef and useEffect.

```tsx
import { RigidBody, RapierRigidBody } from "@react-three/rapier";

const Scene = () => {
  const rigidBody = useRef<RapierRigidBody>(null);

  useEffect(() => {
    if (rigidBody.current) {
      // A one-off "push"
      rigidBody.current.applyImpulse({ x: 0, y: 10, z: 0 }, true);

      // A continuous force
      rigidBody.current.addForce({ x: 0, y: 10, z: 0 }, true);

      // A one-off torque rotation
      rigidBody.current.applyTorqueImpulse({ x: 0, y: 10, z: 0 }, true);

      // A continuous torque
      rigidBody.current.addTorque({ x: 0, y: 10, z: 0 }, true);
    }
  }, []);

  return (
    <RigidBody ref={rigidBody}>
      <mesh>
        <boxBufferGeometry />
        <meshStandardMaterial />
      </mesh>
    </RigidBody>
  );
};
```

